import React, { useState, useMemo } from "react";
import { Card, Typography, Row, Col, Space, Breadcrumb, theme, Select, Button } from "antd";
import { PieChartOutlined, HomeOutlined, DownloadOutlined, FilterOutlined } from "@ant-design/icons";
import EChart from "@/framework/components/Chart/EChart";
import { useI18n } from "@/framework/i18n/hooks";
import { mockStorages } from "../../dashboard/data/mockData";
import { faker } from "@faker-js/faker";

const { Title } = Typography;

export default function StatQuarterPage() {
  const { token } = theme.useToken();
  const { t } = useI18n(["storageLocker", "common"]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const option = useMemo(() => {
    const targets = selectedIds.length > 0 
      ? mockStorages.filter(s => selectedIds.includes(s.id))
      : mockStorages.slice(0, 5);

    return {
      tooltip: { trigger: "item" },
      legend: { top: 0, left: "center", orient: "horizontal" },
      series: [
        {
          name: t("storageLocker:statistics.quarter.usage"),
          type: "pie",
          radius: ["40%", "70%"],
          avoidLabelOverlap: false,
          itemStyle: { borderRadius: 10, borderColor: "#fff", borderWidth: 2 },
          label: { show: false, position: "center" },
          emphasis: { label: { show: true, fontSize: 20, fontWeight: "bold" } },
          labelLine: { show: false },
          data: targets.map(locker => ({ 
            value: faker.number.int({ min: 100, max: 1000 }), 
            name: locker.name 
          })),
        },
      ],
    };
  }, [selectedIds]);

  return (
    <div style={{ padding: 24, display: "flex", flexDirection: "column", gap: 24 }}>
      <Breadcrumb
        items={[
          { title: <HomeOutlined />, href: "/" },
          { title: t("storageLocker:navigation.statistics") },
          { title: t("storageLocker:navigation.statQuarter") },
        ]}
      />

      <Card bordered={false} bodyStyle={{ padding: "16px 24px" }} style={{ boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
        <Row gutter={[16, 16]} align="middle">
          <Col md={8} lg={6}>
            <Title level={4} style={{ margin: 0 }}>
              <PieChartOutlined style={{ marginRight: 8, color: "#722ed1" }} />
              {t("storageLocker:navigation.statQuarter")}
            </Title>
          </Col>
          <Col flex="auto">
            <Row gutter={16} justify="end">
              <Col span={10}>
                <Select 
                  mode="multiple"
                  placeholder={t("storageLocker:dashboard.selectPlaceholder")}
                  style={{ width: "100%" }}
                  maxTagCount="responsive"
                  value={selectedIds}
                  onChange={setSelectedIds}
                  options={mockStorages.map(s => ({ label: s.name, value: s.id }))}
                  allowClear
                />
              </Col>
              <Col>
                <Space>
                  <Select defaultValue="2026-Q1" style={{ width: 120 }}>
                    <Select.Option value="2026-Q1">2026 Q1</Select.Option>
                    <Select.Option value="2025-Q4">2025 Q4</Select.Option>
                  </Select>
                  <Button type="primary" icon={<FilterOutlined />}>{t("common:search")}</Button>
                  <Button icon={<DownloadOutlined />}>{t("common:exportXlsx")}</Button>
                </Space>
              </Col>
            </Row>
          </Col>
        </Row>
      </Card>

      <Row gutter={24}>
        <Col span={12}>
          <Card title={t("storageLocker:statistics.quarter.share")} bordered={false} style={{ boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
            <EChart option={option} style={{ height: 350 }} />
          </Card>
        </Col>
        <Col span={12}>
          <Card title={t("storageLocker:statistics.quarter.faultTrend")} bordered={false} style={{ boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
             <EChart option={{
               xAxis: { type: 'category', data: ['Jan', 'Feb', 'Mar'] },
               yAxis: { type: 'value' },
               series: [{ data: [12, 19, 11], type: 'bar' }]
             }} style={{ height: 350 }} />
          </Card>
        </Col>
      </Row>
    </div>
  );
}
